const instanceUsageLatestPerInstance = `-- name: InstanceUsageLatestPerInstance :many
SELECT DISTINCT ON (s.deployment_instance_id)
    s.deployment_instance_id,
    s.sampled_at,
    s.cpu_nanos_cumulative,
    s.cpu_percent,
    s.memory_rss_bytes,
    s.disk_read_bytes,
    s.disk_write_bytes,
    s.source,
    s.server_id
FROM instance_usage_samples s
INNER JOIN deployment_instances di ON di.id = s.deployment_instance_id
  AND di.deleted_at IS NULL
  AND di.status = 'running'
  AND di.vm_id IS NOT NULL
INNER JOIN deployments d ON d.id = di.deployment_id
  AND d.deleted_at IS NULL
  AND d.project_id = s.project_id
WHERE s.project_id = $1
  AND s.sampled_at >= $2
ORDER BY s.deployment_instance_id, s.sampled_at DESC
`

type InstanceUsageLatestPerInstanceParams struct {
	ProjectID pgtype.UUID        `json:"project_id"`
	SampledAt pgtype.Timestamptz `json:"sampled_at"`
}

type InstanceUsageLatestPerInstanceRow struct {
	DeploymentInstanceID pgtype.UUID        `json:"deployment_instance_id"`
	SampledAt            pgtype.Timestamptz `json:"sampled_at"`
	CpuNanosCumulative   int64              `json:"cpu_nanos_cumulative"`
	CpuPercent           pgtype.Float8      `json:"cpu_percent"`
	MemoryRssBytes       int64              `json:"memory_rss_bytes"`
	DiskReadBytes        int64              `json:"disk_read_bytes"`
	DiskWriteBytes       int64              `json:"disk_write_bytes"`
	Source               string             `json:"source"`
	ServerID             pgtype.UUID        `json:"server_id"`
}

func (q *Queries) InstanceUsageLatestPerInstance(ctx context.Context, arg InstanceUsageLatestPerInstanceParams) ([]InstanceUsageLatestPerInstanceRow, error) {
	rows, err := q.db.Query(ctx, instanceUsageLatestPerInstance, arg.ProjectID, arg.SampledAt)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []InstanceUsageLatestPerInstanceRow{}
	for rows.Next() {
		var i InstanceUsageLatestPerInstanceRow
		if err := rows.Scan(
			&i.DeploymentInstanceID,
			&i.SampledAt,
			&i.CpuNanosCumulative,
			&i.CpuPercent,
			&i.MemoryRssBytes,
			&i.DiskReadBytes,
			&i.DiskWriteBytes,
			&i.Source,
			&i.ServerID,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

